function buildSection<T extends string>(source: Record<T, LocalizedValues>, index: number): Record<T, string> {
    const result = {} as Record<T, string>
    const keys = Object.keys(source) as T[]
    for (let i = 0; i < keys.length; i++) {
        const key = keys[i]
        result[key] = source[key][index]
    }
    return result
}

function buildCatalogs(): Record<LanguageCode, ClientDictionaryType> {
    const result = {} as Record<LanguageCode, ClientDictionaryType>
    for (let i = 0; i < SUPPORTED_LANGUAGE_CODES.length; i++) {
        const lang = SUPPORTED_LANGUAGE_CODES[i]
        result[lang] = {
            system: buildSection(SYSTEM_TRANSLATIONS, i),
            ui: buildSection(UI_TRANSLATIONS, i) as UiMessages,
            primeReact: buildSection(PRIME_TRANSLATIONS, i) as PrimeReactMessages,
        }
    }
    return result
}

export const CLIENT_DICTIONARIES = buildCatalogs()

export function getClientCatalog(locale: string): ClientDictionaryType {
    if (!isSupportedLanguage(locale)) throw new Error(`Unsupported UI language: ${locale}`)
    return CLIENT_DICTIONARIES[locale]
}
